// 1. Получаем массив всех админов из конкретной ноды
const adminsArray = $('Все админы канала').all();

// 2. Получаем данные о канале из триггерной ноды
const channelInfo = $('Бот назначен Админом канала').first().json.my_chat_member;

// 3. Собираем ID только людей (не ботов)
const adminIds = adminsArray
  .filter(item => !item.json.user.is_bot)
  .map(item => item.json.user.id);

// 4. Итоговый объект для Postgres
return {
  channel_name: channelInfo.chat.title,
  channel_id: channelInfo.chat.id,
  admins: JSON.stringify(adminIds)
};

const msg = $("Личное сообщение").first().json.message;
const text = msg.text || "";
const parts = text.split(" ");

let channel_id = 0;
let invite = null;

// Если после /start что-то есть
if (parts.length > 1) {
  const param = parts[1]; // берем n_word

  // Регулярка: число, потом подчеркивание, потом слово (буквы, цифры, тире)
  const match = param.match(/^(\d+)_([a-zA-Z0-9-]+)$/);

  if (match) {
    channel_id = parseInt(match[1], 10);
    invite = match[2];
  } else {
    // Если параметр есть, но не по формату — вызываем ошибку
    throw new Error(`Invalid start parameter format: ${param}. Expected n_word (eПоиск канала1.g. 123_promo-code)`);
  }
}

return {
  channel_id: channel_id,
  user_id: msg.from.id,
  username: msg.from.username || "",
  first_name: msg.from.first_name || "",
  last_name: msg.from.last_name || "",
  invite: invite || "",
  state: {} // для JSONB в PostgreSQL
};

// Получаем значение поля is_blocked из входящего элемента
const isBlocked = $input.first().json.is_blocked;
let message = "";

if (isBlocked === true) {
  // Текст, если пользователь НЕ заблокирован
  message = `🔑 Вы запросили права на управление ботом **Привратником**.
⏳ После одобрения администратором, вы сможете добавлять бота в 📢 каналы и создавать 📝 задания.`;
} else {
  // Текст, если пользователь заблокирован (is_blocked равен true или поле отсутствует)
  message = `🔑 Вы можете управление ботом Привратником.`;
}

// Возвращаем результат в формате n8n
return {
  json: {
    text: message
  }
};

